	assigned := make([]bool, n)
	sccCount := 0

	var dfs func(v int)
	dfs = func(v int) {
		preorder[v] = counter; counter++
		sStack = append(sStack, v)
		pStack = append(pStack, v)

		for _, w := range adj[v] {
			if preorder[w] == -1 {
				dfs(w)
			} else if !assigned[w] {
				for len(pStack) > 0 && preorder[pStack[len(pStack)-1]] > preorder[w] {
					pStack = pStack[:len(pStack)-1]
				}
			}
		}

		if len(pStack) > 0 && pStack[len(pStack)-1] == v {
			pStack = pStack[:len(pStack)-1]
			sccCount++
			for {
				u := sStack[len(sStack)-1]
				sStack = sStack[:len(sStack)-1]
				assigned[u] = true
				if u == v { break }
			}
		}
	}

	for v := 0; v < n; v++ {
		if preorder[v] == -1 { dfs(v) }
	}
	return sccCount
}

import java.util.*;

public class StronglyConnectedPathBased {

    public static int stronglyConnectedPathBased(int[] arr) {
        int n = arr[0], m = arr[1];
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
        for (int i = 0; i < m; i++) {
            adj.get(arr[2 + 2 * i]).add(arr[2 + 2 * i + 1]);
        }

        int[] preorder = new int[n];
        Arrays.fill(preorder, -1);
        int[] counter = {0};
        Deque<Integer> sStack = new ArrayDeque<>();
        Deque<Integer> pStack = new ArrayDeque<>();
        boolean[] assigned = new boolean[n];
        int[] sccCount = {0};

        for (int v = 0; v < n; v++) {
            if (preorder[v] == -1) dfs(v, adj, preorder, counter, sStack, pStack, assigned, sccCount);
        }

        return sccCount[0];
    }

    private static void dfs(int v, List<List<Integer>> adj, int[] preorder, int[] counter,
                            Deque<Integer> sStack, Deque<Integer> pStack, boolean[] assigned, int[] sccCount) {
        preorder[v] = counter[0]++;
        sStack.push(v);
        pStack.push(v);

        for (int w : adj.get(v)) {
            if (preorder[w] == -1) {
                dfs(w, adj, preorder, counter, sStack, pStack, assigned, sccCount);
            } else if (!assigned[w]) {
                while (preorder[pStack.peek()] > preorder[w]) pStack.pop();
            }
        }

        if (!pStack.isEmpty() && pStack.peek() == v) {
            pStack.pop();
            sccCount[0]++;
            while (true) {
                int u = sStack.pop();
                assigned[u] = true;
                if (u == v) break;
            }
        }
    }
}

fun stronglyConnectedPathBased(arr: IntArray): Int {
    val n = arr[0]; val m = arr[1]
    val adj = Array(n) { mutableListOf<Int>() }
    for (i in 0 until m) adj[arr[2 + 2 * i]].add(arr[2 + 2 * i + 1])

    val preorder = IntArray(n) { -1 }
    var counter = 0; var sccCount = 0
    val sStack = ArrayDeque<Int>(); val pStack = ArrayDeque<Int>()
    val assigned = BooleanArray(n)

    fun dfs(v: Int) {
        preorder[v] = counter++
        sStack.addLast(v); pStack.addLast(v)
        for (w in adj[v]) {
            if (preorder[w] == -1) dfs(w)
            else if (!assigned[w]) {
                while (pStack.isNotEmpty() && preorder[pStack.last()] > preorder[w]) pStack.removeLast()
            }
        }
        if (pStack.isNotEmpty() && pStack.last() == v) {
            pStack.removeLast(); sccCount++
            while (true) {
                val u = sStack.removeLast(); assigned[u] = true
                if (u == v) break
            }
        }
    }

    for (v in 0 until n) { if (preorder[v] == -1) dfs(v) }
    return sccCount
}

def strongly_connected_path_based(arr: list[int]) -> int:
    n = arr[0]
    m = arr[1]
    adj = [[] for _ in range(n)]
    for i in range(m):
        u = arr[2 + 2 * i]
        v = arr[2 + 2 * i + 1]
        adj[u].append(v)

    preorder = [-1] * n
    counter = [0]
    s_stack = []
    p_stack = []
    assigned = [False] * n
    scc_count = [0]

    def dfs(v):
        preorder[v] = counter[0]
        counter[0] += 1
        s_stack.append(v)
        p_stack.append(v)

        for w in adj[v]:
            if preorder[w] == -1:
                dfs(w)
            elif not assigned[w]:
                while preorder[p_stack[-1]] > preorder[w]:
                    p_stack.pop()

        if p_stack and p_stack[-1] == v:
            p_stack.pop()
            scc_count[0] += 1
            while True:
                u = s_stack.pop()
                assigned[u] = True
                if u == v:
                    break

    for v in range(n):
        if preorder[v] == -1:
            dfs(v)

    return scc_count[0]

pub fn strongly_connected_path_based(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let m = arr[1] as usize;
    let mut adj = vec![vec![]; n];
    for i in 0..m {
        let u = arr[2 + 2 * i] as usize;
        let v = arr[2 + 2 * i + 1] as usize;
        adj[u].push(v);
    }

    let mut preorder = vec![-1i32; n];
    let mut counter = 0i32;
    let mut s_stack = Vec::new();
    let mut p_stack = Vec::new();
    let mut assigned = vec![false; n];
    let mut scc_count = 0i32;

    fn dfs(
        v: usize, adj: &[Vec<usize>], preorder: &mut [i32], counter: &mut i32,
        s_stack: &mut Vec<usize>, p_stack: &mut Vec<usize>, assigned: &mut [bool], scc_count: &mut i32,
    ) {
        preorder[v] = *counter; *counter += 1;
        s_stack.push(v); p_stack.push(v);

        for &w in &adj[v] {
            if preorder[w] == -1 {
                dfs(w, adj, preorder, counter, s_stack, p_stack, assigned, scc_count);
            } else if !assigned[w] {
                while !p_stack.is_empty() && preorder[*p_stack.last().unwrap()] > preorder[w] {
                    p_stack.pop();
                }
            }
        }

        if !p_stack.is_empty() && *p_stack.last().unwrap() == v {
            p_stack.pop();
            *scc_count += 1;
            loop {
                let u = s_stack.pop().unwrap();
                assigned[u] = true;
                if u == v { break; }
            }
        }
    }

    for v in 0..n {
        if preorder[v] == -1 {
            dfs(v, &adj, &mut preorder, &mut counter, &mut s_stack, &mut p_stack, &mut assigned, &mut scc_count);
        }
    }
    scc_count
}

object StronglyConnectedPathBased {

  def stronglyConnectedPathBased(arr: Array[Int]): Int = {
    val n = arr(0); val m = arr(1)
    val adj = Array.fill(n)(scala.collection.mutable.ListBuffer[Int]())
    for (i <- 0 until m) adj(arr(2 + 2 * i)) += arr(2 + 2 * i + 1)

    val preorder = Array.fill(n)(-1)
    var counter = 0; var sccCount = 0
    val sStack = scala.collection.mutable.Stack[Int]()
    val pStack = scala.collection.mutable.Stack[Int]()
    val assigned = Array.fill(n)(false)

    def dfs(v: Int): Unit = {
      preorder(v) = counter; counter += 1
      sStack.push(v); pStack.push(v)
      for (w <- adj(v)) {
        if (preorder(w) == -1) dfs(w)
        else if (!assigned(w)) {
          while (pStack.nonEmpty && preorder(pStack.top) > preorder(w)) pStack.pop()
        }
      }
      if (pStack.nonEmpty && pStack.top == v) {
        pStack.pop(); sccCount += 1
        var done = false
        while (!done) {
          val u = sStack.pop(); assigned(u) = true
          if (u == v) done = true
        }
      }
    }

    for (v <- 0 until n) { if (preorder(v) == -1) dfs(v) }
    sccCount
  }
}

func stronglyConnectedPathBased(_ arr: [Int]) -> Int {
    let n = arr[0]; let m = arr[1]
    var adj = [[Int]](repeating: [], count: n)
    for i in 0..<m { adj[arr[2 + 2 * i]].append(arr[2 + 2 * i + 1]) }

    var preorder = [Int](repeating: -1, count: n)
    var counter = 0; var sccCount = 0
    var sStack = [Int](); var pStack = [Int]()
    var assigned = [Bool](repeating: false, count: n)

    func dfs(_ v: Int) {
        preorder[v] = counter; counter += 1
        sStack.append(v); pStack.append(v)
        for w in adj[v] {
            if preorder[w] == -1 { dfs(w) }
            else if !assigned[w] {
                while !pStack.isEmpty && preorder[pStack.last!] > preorder[w] { pStack.removeLast() }
            }
        }
        if !pStack.isEmpty && pStack.last! == v {
            pStack.removeLast(); sccCount += 1
            while true {
                let u = sStack.removeLast(); assigned[u] = true
                if u == v { break }
            }
        }
    }

    for v in 0..<n { if preorder[v] == -1 { dfs(v) } }
    return sccCount
}

export function stronglyConnectedPathBased(arr: number[]): number {
    const n = arr[0], m = arr[1];
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (let i = 0; i < m; i++) adj[arr[2 + 2 * i]].push(arr[2 + 2 * i + 1]);

    const preorder = new Array(n).fill(-1);
    let counter = 0, sccCount = 0;
    const sStack: number[] = [], pStack: number[] = [];
    const assigned = new Array(n).fill(false);

    function dfs(v: number): void {
        preorder[v] = counter++;
        sStack.push(v); pStack.push(v);

        for (const w of adj[v]) {
            if (preorder[w] === -1) {
                dfs(w);
            } else if (!assigned[w]) {
                while (pStack.length > 0 && preorder[pStack[pStack.length - 1]] > preorder[w]) pStack.pop();
            }
        }

        if (pStack.length > 0 && pStack[pStack.length - 1] === v) {
            pStack.pop();
            sccCount++;
            while (true) {
                const u = sStack.pop()!;
                assigned[u] = true;
                if (u === v) break;
            }
        }
    }

    for (let v = 0; v < n; v++) {
        if (preorder[v] === -1) dfs(v);
    }
    return sccCount;
}
